  flashcards: [
    {front: "מהי ההגדרה של קורוזיה?", back: "התקפה הרסנית ובלתי-מכוונת על מתכת, בעלת אופי אלקטרוכימי, המתחילה על פני השטח."},
    {front: "היכן מתרחשת תגובת חמצון, ואיפה חיזור?", back: "חמצון באנודה (איבוד אלקטרונים); חיזור בקתודה (קליטת אלקטרונים)."},
    {front: "מהי אלקטרודת המימן הסטנדרטית?", back: "אלקטרודת פלטינה בתמיסת H⁺ 1M הרוויה בגז מימן, המשמשת ייחוס למדידת פוטנציאלי חצי-תא."},
    {front: "מה ההבדל בין טור ה-emf הסטנדרטי לטור הגלווני?", back: "emf — מתכות טהורות ב-1M, 25°C (אידיאלי); גלווני — סגסוגות מסחריות במי ים (מעשי)."},
    {front: "מתי משוואת נרנסט עשויה להפוך את כיוון התגובה הספונטני?", back: "כאשר ריכוזי היונים בתמיסה שונים משמעותית מ-1M, בניגוד לתנאי הטור הסטנדרטי."},
    {front: "מהי נוסחת קצב חדירת הקורוזיה (CPR)?", back: "CPR = K·W/(ρ·A·t), כאשר K=534 ל-mpy או 87.6 ל-mm/yr."},
    {front: "מהי פוליריזציית הפעלה?", back: "פוליריזציה הנשלטת על ידי השלב האיטי ביותר ברצף תגובות הממשק אלקטרודה-אלקטרוליט."},
    {front: "מהי פוליריזציית ריכוז?", back: "פוליריזציה הנשלטת על ידי קצב הדיפוזיה של יונים בתמיסה אל האלקטרודה."},
    {front: "איך מוצאים את קצב הקורוזיה בפועל מעקומות פוליריזציה?", back: "בנקודת החיתוך של עקומות החמצון והחיזור — שם מתקבלים פוטנציאל וצפיפות זרם הקורוזיה."},
    {front: "מהי פסיביות, ואילו מתכות מציגות אותה?", back: "אובדן תגובתיות עקב שכבת תחמוצת מגנה; מוצגת בכרום, ברזל, ניקל, טיטניום וסגסוגותיהם (כולל פלדות אל-חלד)."},
    {front: "מהן שמונה צורות הקורוזיה?", back: "אחידה, גלוונית, סדק, נקודתית, בין-גבישית, סינון סלקטיבי, קורוזיה-שחיקה, קורוזיית מאמצים."},
    {front: "כיצד ניתן להבחין בין קורוזיית מאמצים להתפרכות מהמימן?", back: "הגנה קתודית מפחיתה קורוזיית מאמצים, אך עלולה דווקא להחמיר התפרכות מהמימן."},
    {front: "מהי הגנה קתודית, ואילו שתי טכניקות עיקריות קיימות?", back: "הפיכת המתכת המוגנת לקתודה; באמצעות אנודה מקורבנת (Mg/Zn) או זרם מוטבע ממקור DC חיצוני."},
    {front: "מהו יחס פילינג-בדוורת', ומה משמעות יחס קרוב ל-1?", back: "יחס נפחים תחמוצת/מתכת; יחס קרוב ל-1 (בטווח 1–2) מייצר שכבת חמצון מגנה ודביקה."},
    {front: "מה ההבדל בין קורוזיית מתכות לקורוזיית קרמיקה?", back: "מתכות — תהליך אלקטרוכימי; קרמיקה — המסה כימית פשוטה, עמידה מאוד."},
    {front: "מהם שני מנגנוני הדגרדציה העיקריים בפולימרים?", back: "נפיחות/המסה בחשיפה לנוזל, וקרע שרשראות (גזירה) מקרינה, חום או תגובה כימית."}
  ],

